//! Whisper audio encoder (Pneuma STT, Track A).
//!
//! Reference: arXiv 2212.04356 (Whisper — Robust Speech Recognition via
//! Large-Scale Weak Supervision, Radford et al. 2022).
//! https://arxiv.org/abs/2212.04356
//!
//! Consumes a log-mel spectrogram (`n_mels` × `n_frames=3000`) and produces a
//! row-major audio context tensor of shape (`n_audio_ctx=1500`, `hidden_dim`)
//! that the [`WhisperDecoder`](crate::model_whisper_decoder) cross-attends to.
//!
//! Pipeline (matches OpenAI Whisper / HF `WhisperEncoder`):
//! 1. Conv1d(80 -> hidden, k=3, stride=1, pad=1) + GELU
//! 2. Conv1d(hidden -> hidden, k=3, stride=2, pad=1) + GELU
//! 3. Transpose to (1500, hidden), add learned positional embedding
//! 4. N x { pre-LN, multi-head self-attention (no causal mask), residual,
//!         pre-LN, MLP (fc1 -> GELU -> fc2), residual }
//! 5. Final LayerNorm
//!
//! Buffers are allocated once at construction time and reused across forward
//! passes — same shape contract every utterance (encoder input is always padded
//! to 30 s of audio, i.e. `n_frames=3000`). Mirrors the per-pipeline buffer
//! pattern used by [`crate::model::NativeLlamaPipeline`].

use std::sync::Arc;

// AGENT-STUB: Agent A's deliverable. Signatures defined in
// PNEUMA_CONTRACTS.md. Agent A owns `src/math_pneuma.rs`.
use crate::math_pneuma::{conv1d, conv1d_out_len};

use crate::math::{
    accumulate_weighted, dot_product, gelu_inplace, layer_norm, mat_vec_f32_batch, softmax,
};
use gnosis_frf::prelude::*;

// AGENT-STUB: Agent D's deliverable. Signatures defined in PNEUMA_CONTRACTS.md.
// Agent D owns `src/loader_whisper.rs`.
use crate::loader_whisper::{whisper_tensor_name, WhisperConfig};

use crate::loader::WeightBackend;

/// Cached tensor names for one encoder block. Resolving the format string
/// once per block (instead of per forward pass) keeps the hot path free of
/// allocations — same trick `ResolvedLocs` uses in
/// [`crate::model`](crate::model).
#[derive(Debug, Clone)]
struct EncoderBlockNames {
    ln1_w: String,
    ln1_b: String,
    attn_q_w: String,
    attn_q_b: String,
    attn_k_w: String,
    // Whisper attention K projection has no bias (HF omits it). Kept as a
    // dedicated branch in `forward` so the missing tensor never gets fetched.
    attn_v_w: String,
    attn_v_b: String,
    attn_out_w: String,
    attn_out_b: String,
    ln2_w: String,
    ln2_b: String,
    mlp_fc1_w: String,
    mlp_fc1_b: String,
    mlp_fc2_w: String,
    mlp_fc2_b: String,
}

impl EncoderBlockNames {
    fn new(layer: usize) -> Self {
        let s = "encoder";
        let l = Some(layer);
        Self {
            ln1_w: whisper_tensor_name(s, l, "ln1.weight"),
            ln1_b: whisper_tensor_name(s, l, "ln1.bias"),
            attn_q_w: whisper_tensor_name(s, l, "attn_q.weight"),
            attn_q_b: whisper_tensor_name(s, l, "attn_q.bias"),
            attn_k_w: whisper_tensor_name(s, l, "attn_k.weight"),
            attn_v_w: whisper_tensor_name(s, l, "attn_v.weight"),
            attn_v_b: whisper_tensor_name(s, l, "attn_v.bias"),
            attn_out_w: whisper_tensor_name(s, l, "attn_out.weight"),
            attn_out_b: whisper_tensor_name(s, l, "attn_out.bias"),
            ln2_w: whisper_tensor_name(s, l, "ln2.weight"),
            ln2_b: whisper_tensor_name(s, l, "ln2.bias"),
            mlp_fc1_w: whisper_tensor_name(s, l, "mlp_fc1.weight"),
            mlp_fc1_b: whisper_tensor_name(s, l, "mlp_fc1.bias"),
            mlp_fc2_w: whisper_tensor_name(s, l, "mlp_fc2.weight"),
            mlp_fc2_b: whisper_tensor_name(s, l, "mlp_fc2.bias"),
        }
    }
}

/// Cached top-level (non-block) tensor names. Resolved once at `new()`.
#[derive(Debug, Clone)]
struct EncoderTopNames {
    conv1_w: String,
    conv1_b: String,
    conv2_w: String,
    conv2_b: String,
    pos_embed_w: String,
    ln_final_w: String,
    ln_final_b: String,
}

impl EncoderTopNames {
    fn new() -> Self {
        let s = "encoder";
        Self {
            conv1_w: whisper_tensor_name(s, None, "conv1.weight"),
            conv1_b: whisper_tensor_name(s, None, "conv1.bias"),
            conv2_w: whisper_tensor_name(s, None, "conv2.weight"),
            conv2_b: whisper_tensor_name(s, None, "conv2.bias"),
            pos_embed_w: whisper_tensor_name(s, None, "pos_embed.weight"),
            ln_final_w: whisper_tensor_name(s, None, "ln_final.weight"),
            ln_final_b: whisper_tensor_name(s, None, "ln_final.bias"),
        }
    }
}

/// Whisper encoder: log-mel spectrogram -> audio context tensor.
///
/// Construction is cheap; weight bytes are fetched lazily per `forward()` via
/// the `backend` (mmap is zero-copy, HTTP is range-fetched and LRU-cached).
/// Internal scratch buffers are sized at `new()` from the supplied
/// [`WhisperConfig`] and reused across calls.
///
/// Two forward modes are available:
///   * [`forward`](Self::forward) — one-shot, takes a fully padded
///     `(n_mels, 3000)` mel and returns the encoder output.
///   * [`forward_streaming_chunk`](Self::forward_streaming_chunk) +
///     [`forward_streaming_finalize`](Self::forward_streaming_finalize) —
///     incremental: feed mel chunks as they arrive (e.g. one per second of
///     audio), pull a partial encoder output after each chunk. Internally
///     this still re-runs the full encoder over the buffered mel ring on
///     every chunk; see the streaming methods' docs for the trade-off.
pub struct WhisperEncoder {
    /// Audio + transformer dims.
    config: WhisperConfig,
    /// Weight source (mmap, HTTP, or wasm-host backend).
    backend: Arc<dyn WeightBackend>,
    /// Per-block tensor name cache.
    blocks: Vec<EncoderBlockNames>,
    /// Top-level (conv / pos embed / final LN) tensor name cache.
    top: EncoderTopNames,

    // ── Scratch buffers (allocated once, reused per forward) ────────────
    /// Output of conv1: shape (hidden, n_frames=3000), row-major.
    conv1_out: Vec<f32>,
    /// Output of conv2: shape (hidden, n_audio_ctx=1500), row-major.
    conv2_out: Vec<f32>,
    /// Working hidden state in (seq, hidden) layout, the layout the
    /// transformer blocks consume.
    x: Vec<f32>,
    /// Per-token LN/residual scratch (seq, hidden).
    xb: Vec<f32>,
    /// Per-token attention output scratch (seq, hidden).
    attn_out: Vec<f32>,
    /// Per-token Q projections (seq, hidden).
    q_buf: Vec<f32>,
    /// Per-token K projections (seq, hidden).
    k_buf: Vec<f32>,
    /// Per-token V projections (seq, hidden).
    v_buf: Vec<f32>,
    /// MLP intermediate (seq, 4*hidden).
    mlp_buf: Vec<f32>,

    // ── Streaming state (allocated once, reused across utterances) ──────
    /// 30 s mel ring: `(n_mels, 3000)` row-major. Populated incrementally
    /// by [`forward_streaming_chunk`]; the unfilled tail stays at 0.0 so
    /// it is exactly the zero-padding Whisper expects for short audio.
    /// Owned by the encoder so the streaming path is allocation-free
    /// after construction (matches the per-pipeline buffer discipline of
    /// the rest of this struct).
    streaming_mel: Vec<f32>,
    /// Number of mel frames populated in `streaming_mel` so far. Resets
    /// to 0 in [`reset_streaming`]. Saturates at `3000` — chunks past
    /// the 30 s window are silently dropped (same behaviour as one-shot
    /// `forward` truncating the input).
    streaming_frames_filled: usize,
}

impl WhisperEncoder {
    /// Construct an encoder from a parsed config and a weight backend handle.
    /// Pre-resolves all tensor names and allocates scratch buffers.
    pub fn new(config: WhisperConfig, backend: Arc<dyn WeightBackend>) -> Self {
        let hidden = config.encoder_hidden_dim;
        let inter = config.encoder_intermediate_size;
        let seq = config.n_audio_ctx;
        let n_frames = 3000usize; // Whisper standard 30 s window @ 100 Hz.

        let blocks = (0..config.encoder_layers)
            .map(EncoderBlockNames::new)
            .collect();
        let top = EncoderTopNames::new();

        Self {
            blocks,
            top,
            conv1_out: vec![0.0; hidden * n_frames],
            conv2_out: vec![0.0; hidden * seq],
            x: vec![0.0; seq * hidden],
            xb: vec![0.0; seq * hidden],
            attn_out: vec![0.0; seq * hidden],
            q_buf: vec![0.0; seq * hidden],
            k_buf: vec![0.0; seq * hidden],
            v_buf: vec![0.0; seq * hidden],
            mlp_buf: vec![0.0; seq * inter],
            // Streaming ring sized to the full 30 s window so a finalize
            // call always has the right shape to hand to `forward()`.
            streaming_mel: vec![0.0; config.n_mels * n_frames],
            streaming_frames_filled: 0,
            config,
            backend,
        }
    }

    /// Run the encoder forward.
    ///
    /// `mel`: row-major `(n_mels, n_frames=3000)` log-mel spectrogram.
    /// Returns: row-major `(n_audio_ctx=1500, hidden_dim)` audio context.
    ///
    /// Panics if `mel.len() != n_mels * 3000`.
    pub fn forward(&mut self, mel: &[f32]) -> Vec<f32> {
        let cfg = &self.config;
        let hidden = cfg.encoder_hidden_dim;
        let inter = cfg.encoder_intermediate_size;
        let seq = cfg.n_audio_ctx;
        let n_mels = cfg.n_mels;
        let n_frames = 3000usize;
        let eps = cfg.eps;

        assert_eq!(
            mel.len(),
            n_mels * n_frames,
            "WhisperEncoder.forward: expected mel of length {} ({} mels x {} frames), got {}",
            n_mels * n_frames,
            n_mels,
            n_frames,
            mel.len(),
        );

        // ── 1. Conv stem ────────────────────────────────────────────────
        // Conv1: in_ch=n_mels, out_ch=hidden, k=3, stride=1, pad=1.
        let conv1_out_len = conv1d_out_len(n_frames, 3, 1, 1);
        debug_assert_eq!(conv1_out_len, n_frames, "conv1 should preserve length");
        {
            let conv1_w = self.backend.fetch_tensor(&self.top.conv1_w).unwrap();
            let conv1_b = self.backend.fetch_tensor(&self.top.conv1_b).unwrap();
            conv1d(
                &mut self.conv1_out,
                mel,
                bytes_to_f32_slice(&conv1_w),
                Some(bytes_to_f32_slice(&conv1_b)),
                n_mels,
                hidden,
                n_frames,
                3,
                1,
                1,
            );
        }
        gelu_inplace(&mut self.conv1_out);

        // Conv2: in_ch=hidden, out_ch=hidden, k=3, stride=2, pad=1 -> halves length.
        let conv2_out_len = conv1d_out_len(conv1_out_len, 3, 2, 1);
        debug_assert_eq!(conv2_out_len, seq, "conv2 should yield n_audio_ctx frames");
        {
            let conv2_w = self.backend.fetch_tensor(&self.top.conv2_w).unwrap();
            let conv2_b = self.backend.fetch_tensor(&self.top.conv2_b).unwrap();
            conv1d(
                &mut self.conv2_out,
                &self.conv1_out,
                bytes_to_f32_slice(&conv2_w),
                Some(bytes_to_f32_slice(&conv2_b)),
                hidden,
                hidden,
                conv1_out_len,
                3,
                2,
                1,
            );
        }
        gelu_inplace(&mut self.conv2_out);

        // ── 2. Transpose (hidden, seq) -> (seq, hidden), add positional embed ─
        {
            let pos_w = self.backend.fetch_tensor(&self.top.pos_embed_w).unwrap();
            let pos = bytes_to_f32_slice(&pos_w);
            for t in 0..seq {
                let row = &mut self.x[t * hidden..(t + 1) * hidden];
                for h in 0..hidden {
                    // conv2_out is laid out (out_ch=hidden, out_len=seq) row-major,
                    // i.e. all timesteps for channel 0, then channel 1, ...
                    row[h] = self.conv2_out[h * seq + t] + pos[t * hidden + h];
                }
            }
        }

        // ── 3. Encoder blocks ──────────────────────────────────────────
        for l in 0..cfg.encoder_layers {
            self.encoder_block(l, hidden, inter, seq, eps);
        }

        // ── 4. Final LayerNorm (per-token) ─────────────────────────────
        {
            let ln_w = self.backend.fetch_tensor(&self.top.ln_final_w).unwrap();
            let ln_b = self.backend.fetch_tensor(&self.top.ln_final_b).unwrap();
            let ln_w_f = bytes_to_f32_slice(&ln_w);
            let ln_b_f = bytes_to_f32_slice(&ln_b);
            for t in 0..seq {
                let off = t * hidden;
                // LayerNorm reads x in-place; route through xb to avoid aliasing.
                let (src, dst) = (&self.x[off..off + hidden], &mut self.xb[off..off + hidden]);
                layer_norm(dst, src, ln_w_f, ln_b_f, eps);
            }
            std::mem::swap(&mut self.x, &mut self.xb);
        }

        // Return shape (seq, hidden) as a flat Vec — caller (decoder /
        // wasm bridge) treats it as the cross-attention K/V source.
        self.x.clone()
    }

    /// Streaming encoder: write a partial mel chunk into the internal 30 s
    /// mel ring. Subsequent chunks append after the previous one.
    ///
    /// `chunk_mel` is row-major `(n_mels, chunk_n_frames)`. `chunk_n_frames`
    /// is inferred from `chunk_mel.len() / n_mels`. `chunk_index` is the
    /// 0-based position of this chunk in the utterance and is used purely
    /// for the panic message — placement in the ring is sequential, driven
    /// by the running `streaming_frames_filled` cursor (i.e. callers MUST
    /// feed chunks in order; out-of-order indices are not supported in v1).
    ///
    /// Chunks past the 30 s window are silently truncated, matching the
    /// one-shot `forward()` contract. No compute happens here — call
    /// [`forward_streaming_finalize`] to get the partial encoder output.
    ///
    /// Panics if `chunk_mel.len()` is not a multiple of `n_mels`.
    ///
    /// TODO: real chunked attention with cached K/V across chunks for
    /// sub-utterance latency. v1 trades CPU for simplicity — finalize
    /// re-runs the full encoder over the buffered ring on each call,
    /// which costs an extra `O(N)` full forwards for `N` chunks but
    /// avoids the careful KV-cache + lookahead bookkeeping that real
    /// streaming attention needs.
    pub fn forward_streaming_chunk(&mut self, chunk_mel: &[f32], chunk_index: usize) {
        let n_mels = self.config.n_mels;
        let n_frames = 3000usize;
        assert!(
            chunk_mel.len().is_multiple_of(n_mels),
            "WhisperEncoder.forward_streaming_chunk: chunk mel length {} not divisible by n_mels={} (chunk_index={})",
            chunk_mel.len(),
            n_mels,
            chunk_index,
        );
        let chunk_frames = chunk_mel.len() / n_mels;
        if chunk_frames == 0 {
            // Nothing to copy. Treat zero-length chunks as a no-op so
            // callers can use them as keep-alives if they want.
            return;
        }

        let cursor = self.streaming_frames_filled;
        if cursor >= n_frames {
            // Ring already saturated — drop the chunk silently. Mirrors
            // the way `forward` would truncate the audio at 30 s.
            return;
        }
        let remaining = n_frames - cursor;
        let copy_frames = chunk_frames.min(remaining);

        // The mel ring is stored row-major as (n_mels, n_frames): all
        // timesteps for mel-bin 0 come first, then mel-bin 1, etc. The
        // incoming chunk uses the same layout, so for each mel-bin we
        // splat its `copy_frames` slice into the bin's ring row at the
        // current cursor.
        for m in 0..n_mels {
            let src_off = m * chunk_frames;
            let dst_off = m * n_frames + cursor;
            self.streaming_mel[dst_off..dst_off + copy_frames]
                .copy_from_slice(&chunk_mel[src_off..src_off + copy_frames]);
        }
        self.streaming_frames_filled = cursor + copy_frames;
    }

    /// Run the full encoder forward over the currently buffered streaming
    /// mel ring and return the resulting `(n_audio_ctx, hidden)` output.
    ///
    /// Frames past `streaming_frames_filled` are zero (we initialised the
    /// ring at 0.0 and `reset_streaming` re-zeroes only the populated
    /// prefix), which is the same zero-padding Whisper applies to short
    /// audio in the one-shot path.
    ///
    /// Safe to call multiple times for the same utterance (idempotent in
    /// the buffer state) — each call yields a fresh `Vec<f32>` snapshot.
    /// Call [`reset_streaming`] before starting a new utterance.
    ///
    /// TODO: real chunked attention with cached K/V across chunks for
    /// sub-utterance latency.
    pub fn forward_streaming_finalize(&mut self) -> Vec<f32> {
        // Take the mel ring out of `self` temporarily so we can pass an
        // immutable slice into `forward` (which needs `&mut self` for the
        // scratch buffers). Replace with an empty Vec, then put the ring
        // back. This avoids cloning the full 240 KB mel tensor.
        let mel = std::mem::take(&mut self.streaming_mel);
        let out = self.forward(&mel);
        self.streaming_mel = mel;
        out
    }

    /// Reset streaming state for a new utterance. Zeroes the populated
    /// prefix of the mel ring (only the part `forward_streaming_chunk`
    /// actually touched) and resets the cursor to 0.
    ///
    /// The cross-attention K/V caches in [`crate::model_whisper_decoder::WhisperDecoder`]
    /// are independent of the encoder's streaming state — call
    /// `WhisperDecoder::reset` separately on the decoder.
    pub fn reset_streaming(&mut self) {
        let n_frames = 3000usize;
        let n_mels = self.config.n_mels;
        let filled = self.streaming_frames_filled;
        if filled > 0 {
            // Only zero the prefix of each mel-bin row that was actually
            // written; the remainder was already zero from construction
            // (or from the previous reset).
            for m in 0..n_mels {
                let off = m * n_frames;
                for v in self.streaming_mel[off..off + filled].iter_mut() {
                    *v = 0.0;
                }
            }
        }
        self.streaming_frames_filled = 0;
    }

    /// One encoder block: pre-LN self-attention + residual, pre-LN MLP +
    /// residual. Operates over the full sequence in `self.x`.
    fn encoder_block(&mut self, l: usize, hidden: usize, inter: usize, seq: usize, eps: f32) {
        let names = self.blocks[l].clone();
        let num_heads = self.config.encoder_heads;
        debug_assert_eq!(hidden % num_heads, 0, "hidden must divide num_heads");
        let head_dim = hidden / num_heads;
        let scale = 1.0 / (head_dim as f32).sqrt();

        // ── Pre-attention LayerNorm: xb = ln1(x) ────────────────────────
        {
            let ln1_w = self.backend.fetch_tensor(&names.ln1_w).unwrap();
            let ln1_b = self.backend.fetch_tensor(&names.ln1_b).unwrap();
            let w = bytes_to_f32_slice(&ln1_w);
            let b = bytes_to_f32_slice(&ln1_b);
            for t in 0..seq {
                let off = t * hidden;
                let (src, dst) = (&self.x[off..off + hidden], &mut self.xb[off..off + hidden]);
                layer_norm(dst, src, w, b, eps);
            }
        }

        // ── Q, K, V projections (batched mat-vec) ──────────────────────
        {
            let q_w = self.backend.fetch_tensor(&names.attn_q_w).unwrap();
            let k_w = self.backend.fetch_tensor(&names.attn_k_w).unwrap();
            let v_w = self.backend.fetch_tensor(&names.attn_v_w).unwrap();
            let q_w_f = bytes_to_f32_slice(&q_w);
            let k_w_f = bytes_to_f32_slice(&k_w);
            let v_w_f = bytes_to_f32_slice(&v_w);

            let mut xs = Vec::with_capacity(seq);
            let mut qs = Vec::with_capacity(seq);
            let mut ks = Vec::with_capacity(seq);
            let mut vs = Vec::with_capacity(seq);

            // We need to use unsafe to get multiple mutable slices from the same Vec.
            // This is safe here because the slices are non-overlapping.
            unsafe {
                let xb_ptr = self.xb.as_ptr();
                let q_ptr = self.q_buf.as_mut_ptr();
                let k_ptr = self.k_buf.as_mut_ptr();
                let v_ptr = self.v_buf.as_mut_ptr();
                for t in 0..seq {
                    xs.push(std::slice::from_raw_parts(xb_ptr.add(t * hidden), hidden));
                    qs.push(std::slice::from_raw_parts_mut(
                        q_ptr.add(t * hidden),
                        hidden,
                    ));
                    ks.push(std::slice::from_raw_parts_mut(
                        k_ptr.add(t * hidden),
                        hidden,
                    ));
                    vs.push(std::slice::from_raw_parts_mut(
                        v_ptr.add(t * hidden),
                        hidden,
                    ));
                }
            }

            mat_vec_f32_batch(&mut qs, &xs, q_w_f, hidden, hidden);
            mat_vec_f32_batch(&mut ks, &xs, k_w_f, hidden, hidden);
            mat_vec_f32_batch(&mut vs, &xs, v_w_f, hidden, hidden);

            // Add biases (Q and V have them, K does not).
            let q_b = self.backend.fetch_tensor(&names.attn_q_b).unwrap();
            let v_b = self.backend.fetch_tensor(&names.attn_v_b).unwrap();
            let q_b_f = bytes_to_f32_slice(&q_b);
            let v_b_f = bytes_to_f32_slice(&v_b);
            for t in 0..seq {
                let off = t * hidden;
                for h in 0..hidden {
                    self.q_buf[off + h] += q_b_f[h];
                    self.v_buf[off + h] += v_b_f[h];
                }
            }
        }

        // ── Multi-head self-attention (no causal mask, no RoPE) ─────────
        {
            let q = &self.q_buf;
            let k = &self.k_buf;
            let v = &self.v_buf;
            let attn_dst = &mut self.attn_out;

            // Parallelize over heads and tokens.
            let hidden_ = hidden;
            let num_heads_ = num_heads;
            let head_dim_ = head_dim;
            let seq_ = seq;
            let scale_ = scale;

            // We use a raw pointer to accumulate into attn_dst in parallel.
            // This is safe because each (t, h) pair writes to a unique slice.
            let attn_ptr = attn_dst.as_mut_ptr() as usize;

            (0..seq_).into_par_iter().for_each(|t| {
                let mut scores = vec![0.0f32; seq_];
                for h in 0..num_heads_ {
                    let q_off = t * hidden_ + h * head_dim_;
                    let q_head =
                        unsafe { std::slice::from_raw_parts(q.as_ptr().add(q_off), head_dim_) };

                    // 1) Dot products against every key in the sequence for this head.
                    for s in 0..seq_ {
                        let k_off = s * hidden_ + h * head_dim_;
                        let k_head =
                            unsafe { std::slice::from_raw_parts(k.as_ptr().add(k_off), head_dim_) };
                        scores[s] = dot_product(q_head, k_head) * scale_;
                    }

                    // 2) Softmax
                    softmax(&mut scores);

                    // 3) Weighted sum over values.
                    let out_off = t * hidden_ + h * head_dim_;
                    let head_out = unsafe {
                        std::slice::from_raw_parts_mut(
                            (attn_ptr as *mut f32).add(out_off),
                            head_dim_,
                        )
                    };
                    for v_ in head_out.iter_mut() {
                        *v_ = 0.0;
                    }

                    for s in 0..seq_ {
                        let w = scores[s];
                        let v_off = s * hidden_ + h * head_dim_;
                        let v_head =
                            unsafe { std::slice::from_raw_parts(v.as_ptr().add(v_off), head_dim_) };
                        accumulate_weighted(head_out, v_head, w);
                    }
                }
            });
        }

        // ── Output projection + bias, accumulated back into x (residual) ─
        {
            let o_w = self.backend.fetch_tensor(&names.attn_out_w).unwrap();
            let o_b = self.backend.fetch_tensor(&names.attn_out_b).unwrap();
            let o_w_f = bytes_to_f32_slice(&o_w);
            let o_b_f = bytes_to_f32_slice(&o_b);

            let mut attns = Vec::with_capacity(seq);
            let mut xbs = Vec::with_capacity(seq);
            unsafe {
                let attn_ptr = self.attn_out.as_ptr();
                let xb_ptr = self.xb.as_mut_ptr();
                for t in 0..seq {
                    attns.push(std::slice::from_raw_parts(attn_ptr.add(t * hidden), hidden));
                    xbs.push(std::slice::from_raw_parts_mut(
                        xb_ptr.add(t * hidden),
                        hidden,
                    ));
                }
            }

            mat_vec_f32_batch(&mut xbs, &attns, o_w_f, hidden, hidden);

            for t in 0..seq {
                let off = t * hidden;
                for h in 0..hidden {
                    self.x[off + h] += self.xb[off + h] + o_b_f[h];
                }
            }
        }

        // ── Pre-MLP LayerNorm: xb = ln2(x) ──────────────────────────────
        {
            let ln2_w = self.backend.fetch_tensor(&names.ln2_w).unwrap();
            let ln2_b = self.backend.fetch_tensor(&names.ln2_b).unwrap();
            let w = bytes_to_f32_slice(&ln2_w);
            let b = bytes_to_f32_slice(&ln2_b);
            for t in 0..seq {
                let off = t * hidden;
                let (src, dst) = (&self.x[off..off + hidden], &mut self.xb[off..off + hidden]);
                layer_norm(dst, src, w, b, eps);
            }
        }

        // ── MLP: fc1 (+ bias) -> GELU -> fc2 (+ bias) -> residual ───────
        // fc1: (inter, hidden) matrix applied to seq tokens.
        {
            let fc1_w = self.backend.fetch_tensor(&names.mlp_fc1_w).unwrap();
            let fc1_b = self.backend.fetch_tensor(&names.mlp_fc1_b).unwrap();
            let fc1_w_f = bytes_to_f32_slice(&fc1_w);
            let fc1_b_f = bytes_to_f32_slice(&fc1_b);

            let mut xbs = Vec::with_capacity(seq);
            let mut mlps = Vec::with_capacity(seq);
            unsafe {
                let xb_ptr = self.xb.as_ptr();
                let mlp_ptr = self.mlp_buf.as_mut_ptr();
                for t in 0..seq {
                    xbs.push(std::slice::from_raw_parts(xb_ptr.add(t * hidden), hidden));
                    mlps.push(std::slice::from_raw_parts_mut(
                        mlp_ptr.add(t * inter),
                        inter,
                    ));
                }
            }

            mat_vec_f32_batch(&mut mlps, &xbs, fc1_w_f, inter, hidden);

            for t in 0..seq {
                let off = t * inter;
                for h in 0..inter {
                    self.mlp_buf[off + h] += fc1_b_f[h];
                }
            }
        }
        gelu_inplace(&mut self.mlp_buf);
        // fc2: (hidden, inter) matrix applied to seq tokens.
        {
            let fc2_w = self.backend.fetch_tensor(&names.mlp_fc2_w).unwrap();
            let fc2_b = self.backend.fetch_tensor(&names.mlp_fc2_b).unwrap();
            let fc2_w_f = bytes_to_f32_slice(&fc2_w);
            let fc2_b_f = bytes_to_f32_slice(&fc2_b);

            let mut mlps = Vec::with_capacity(seq);
            let mut xbs = Vec::with_capacity(seq);
            unsafe {
                let mlp_ptr = self.mlp_buf.as_ptr();
                let xb_ptr = self.xb.as_mut_ptr();
                for t in 0..seq {
                    mlps.push(std::slice::from_raw_parts(mlp_ptr.add(t * inter), inter));
                    xbs.push(std::slice::from_raw_parts_mut(
                        xb_ptr.add(t * hidden),
                        hidden,
                    ));
                }
            }

            mat_vec_f32_batch(&mut xbs, &mlps, fc2_w_f, hidden, inter);

            for t in 0..seq {
                let off = t * hidden;
                for h in 0..hidden {
                    self.x[off + h] += self.xb[off + h] + fc2_b_f[h];
                }
            }
        }
    }
}

/// View raw little-endian f32 bytes returned by `WeightBackend::fetch_tensor`
/// as an f32 slice without copying. Mirrors the helper in
/// [`crate::model`](crate::model); kept here to avoid pulling that whole
/// module's namespace into the encoder.
#[inline(always)]
fn bytes_to_f32_slice(bytes: &[u8]) -> &[f32] {
    unsafe { std::slice::from_raw_parts(bytes.as_ptr() as *const f32, bytes.len() / 4) }
}
